export interface AsyncQueueAddOptions {
  signal?: AbortSignal;
}

class AbortError extends Error {
  override name = "AbortError";
  constructor(message = "The operation was aborted") {
    super(message);
  }
}

type QueueItem<T> = {
  fn: TaskFn<T>;
  resolve: (value: T | PromiseLike<T>) => void;
  reject: (reason?: unknown) => void;
  signal?: AbortSignal;
  started: boolean;
  onAbort?: () => void;
};

export class AsyncQueue {
  #concurrency: number;
  #running = 0;
  #queue: Array<QueueItem<unknown>> = [];
  #pumpScheduled = false;
  #idleWaiters: Array<() => void> = [];

  constructor(concurrency = 1) {
    if (!Number.isFinite(concurrency) || concurrency < 1) {
      throw new RangeError("concurrency must be a finite number >= 1");
    }
    this.#concurrency = Math.floor(concurrency);
  }

  get concurrency(): number {
    return this.#concurrency;
  }

  set concurrency(value: number) {
    if (!Number.isFinite(value) || value < 1) {
      throw new RangeError("concurrency must be a finite number >= 1");
    }
    this.#concurrency = Math.floor(value);
    this.#schedulePump();
  }

  get running(): number {
    return this.#running;
  }

  get pending(): number {
    return this.#queue.length;
  }

  get size(): number {
    return this.#running + this.#queue.length;
  }

  add<T>(task: TaskFn<T>, options: AsyncQueueAddOptions = {}): Promise<T> {
    const { signal } = options;

    if (typeof task !== "function") {
      return Promise.reject(new TypeError("task must be a function"));
    }

    if (signal?.aborted) {
      return Promise.reject(signal.reason ?? new AbortError());
    }

    return new Promise<T>((resolve, reject) => {
      const item: QueueItem<T> = {
        fn: task,
        resolve,
        reject,
        signal,
        started: false,
      };

      if (signal) {
        const onAbort = () => {
          if (item.started) return;
          this.#remove(item as QueueItem<unknown>);
          reject(signal.reason ?? new AbortError());
        };
        item.onAbort = onAbort;
        signal.addEventListener("abort", onAbort, { once: true });
      }

      this.#queue.push(item as QueueItem<unknown>);
      this.#schedulePump();
    });
  }

  onIdle(): Promise<void> {
    if (this.#running === 0 && this.#queue.length === 0) return Promise.resolve();
    return new Promise<void>((resolve) => {
      this.#idleWaiters.push(resolve);
    });
  }

  clear(reason: unknown = new Error("Queue cleared")): void {
    const items = this.#queue.splice(0, this.#queue.length);
    for (const item of items) {
      this.#detachAbort(item);
      item.reject(reason);
    }
    this.#maybeResolveIdle();
  }

  #schedulePump(): void {
    if (this.#pumpScheduled) return;
    this.#pumpScheduled = true;
    queueMicrotask(() => {
      this.#pumpScheduled = false;
      this.#pump();
    });
