      const item = this.#queue.shift()!;
      if (item.signal?.aborted) {
        this.#detachAbort(item);
        item.reject(item.signal.reason ?? new AbortError());
        continue;
      }

      item.started = true;
      this.#detachAbort(item);
      this.#running++;

      Promise.resolve()
        .then(() => (item.fn as TaskFn<unknown>)())
        .then(
          (value) => item.resolve(value),
          (err) => item.reject(err),
        )
        .finally(() => {
          this.#running--;
          this.#maybeResolveIdle();
          this.#schedulePump();
        });
