  #maybeResolveIdle(): void {
    if (this.#running !== 0 || this.#queue.length !== 0) return;
    if (this.#idleWaiters.length === 0) return;
    const waiters = this.#idleWaiters.splice(0, this.#idleWaiters.length);
    for (const resolve of waiters) resolve();
