    }
  }

  private next(): void {
    if (this.queue.length > 0 && this.activeCount < this.concurrency) {
      const resolve = this.queue.shift();
      resolve?.();
    }
  }

  get pending(): number {
    return this.queue.length;
  }

  get active(): number {
    return this.activeCount;
  }
}

