use std::collections::HashMap;

#[derive(Default, Debug)]
struct Node {
    term: bool,
    next: HashMap<char, usize>,
}

#[derive(Default, Debug)]
pub struct Trie {
    nodes: Vec<Node>,
}

impl Trie {
    pub fn new() -> Self {
        Self {
            nodes: vec![Node::default()],
        }
    }

    pub fn insert(&mut self, word: &str) {
        let mut i = 0usize;
        for ch in word.chars() {
            let next_i = match self.nodes[i].next.get(&ch).copied() {
                Some(j) => j,
                None => {
                    let j = self.nodes.len();
                    self.nodes.push(Node::default());
                    self.nodes[i].next.insert(ch, j);
                    j
                }
            };
            i = next_i;
        }
        self.nodes[i].term = true;
    }

    pub fn contains(&self, word: &str) -> bool {
        self.walk(word).is_some_and(|i| self.nodes[i].term)
    }

    pub fn starts_with(&self, prefix: &str) -> bool {
        self.walk(prefix).is_some()
    }

    fn walk(&self, s: &str) -> Option<usize> {
        let mut i = 0usize;
        for ch in s.chars() {
            i = *self.nodes[i].next.get(&ch)?;
        }
        Some(i)
    }
}

